const body = $json.body ?? $json;

if (!body.input || !body.prompt) {
  throw new Error('Missing validation input');
}

return [{
  json: {
    input: body.input,
    prompt: body.prompt,
    requestId: body.requestId ?? Date.now().toString()
  }
}];

const content = $json.output?.[0]?.content?.[0]?.text
  ?? $json.output?.content?.[0]?.text
  ?? $json.content?.[0]?.text
  ?? $json.text
  ?? $json.message?.content
  ?? $json.choices?.[0]?.message?.content
  ?? $json.data?.[0]?.content?.[0]?.text
  ?? $json.output
  ?? $json.content
  ?? $json;

if (!content) throw new Error('OpenAI returned no content');

let parsed;
if (typeof content === 'object') {
  parsed = content;
} else {
  try {
    parsed = JSON.parse(content);
  } catch (error) {
    const match = String(content).match(/\{[\s\S]*\}/);
    if (!match) throw new Error('OpenAI returned invalid JSON');
    parsed = JSON.parse(match[0]);
  }
}

if (Array.isArray(parsed?.output)) {
  parsed = parsed.output[0]?.content?.[0]?.text ?? parsed;
}
if (Array.isArray(parsed?.content)) {
  parsed = parsed.content[0]?.text ?? parsed;
}
if (typeof parsed === 'string') {
  parsed = JSON.parse(parsed);
}

const validation = parsed.validation ?? parsed;
const requiredCategories = [
  'curriculum_alignment',
  'syllabus_alignment',
  'year_level_appropriateness',
  'scope_realism',
  'timeline_feasibility',
  'team_size_suitability',
  'workload_balance',
  'skill_coverage',
  'learning_outcome_prediction',
  'rubric_quality',
  'project_type_fit'
];

function clampScore(value) {
  const score = Number(value);
  if (!Number.isFinite(score)) return 0;
  return Math.max(0, Math.min(100, Math.round(score)));
}

function readinessLabel(score) {
  if (score >= 90) return 'Ready for Release';
  if (score >= 75) return 'Ready with Minor Improvements';
  if (score >= 60) return 'Needs Revision';
  return 'High Risk Project';
}

function difficultyLabel(score) {
  if (score >= 85) return 'Capstone-Level';
  if (score >= 70) return 'Advanced';
  if (score >= 40) return 'Intermediate';
  return 'Beginner';
}

const sourceScores = Array.isArray(validation.scores) ? validation.scores : [];
const scores = requiredCategories.map((category) => {
  const score = sourceScores.find((item) => item.category === category) ?? {};
  return {
    category,
    score: clampScore(score.score),
    label: score.label || 'Evaluated',
    explanation: score.explanation || 'Generated from project, class, curriculum, syllabus, rubric, timeline, and historical context.'
  };
});

const readinessScore = clampScore(validation.readinessScore ?? scores.reduce((sum, item) => sum + item.score, 0) / scores.length);
const difficultyScore = clampScore(validation.difficultyScore);

return [{
  json: {
    validation: {
      executiveSummary: validation.executiveSummary || 'Project validation completed. Professor review is required before final release.',
      readinessScore,
      readinessLabel: validation.readinessLabel || readinessLabel(readinessScore),
      difficultyScore,
      difficultyLabel: validation.difficultyLabel || difficultyLabel(difficultyScore),
      scores,
      risks: Array.isArray(validation.risks) ? validation.risks : [],
      recommendations: Array.isArray(validation.recommendations) ? validation.recommendations : [],
      skillCoverage: Array.isArray(validation.skillCoverage) ? validation.skillCoverage : [],
      coveredOutcomes: Array.isArray(validation.coveredOutcomes) ? validation.coveredOutcomes : [],
      missingOutcomes: Array.isArray(validation.missingOutcomes) ? validation.missingOutcomes : [],
      comparisonReport: validation.comparisonReport || 'No comparison report generated.',
      validationReport: validation.validationReport || {}
    }
  }
}];
